script.text:

function load$&Identity;Grid$(g) {
  var f = g.get_element().parentForm, z = f.grid, w = z.get_element().parentForm;
  if (g._rowCount > 0) g._focusWhenTabChanged();
    else try {$get(String.format('{0}_updateDlgCancel', f._id)).focus();} catch (ex) {}
  try {$get('FlowGridTagId').parentNode.title = '';} catch (ex) {}
  render$&Identity;Grid$(g, ['ma_vi_tri', 'ma_lo'], ['gia_nt', 'tien_nt'], z);
}
function scatter$&Identity;Grid$(g) {g._memvars = [];}
function render$&Identity;Grid$(g, c, d, z) {
  var w = z.get_element().parentForm;
  k = z._voucher$Retrieve$Fields.split(String.fromCharCode(255));
  u = (w._baseCurrency.toUpperCase() == k[0]);
  for (var i = 0; i < c.length; i++) {
    var k = z._getColumnOrder($func.trim(c[i])), v = z._fields[k - 1].Visible;
    g._setColumnVisible(g._getColumnOrder($func.trim(c[i])), v);
  }
  for (var i = 0; i < d.length; i++) {
    var k = z._getColumnOrder($func.trim(d[i]));
    g._setColumnVisible(g._getColumnOrder($func.trim(d[i])), !u);
  }
}
function onClick$&Identity;$Calculate(o) {
  var g = o.grid, a = o.id.split('_inputCell_'), r = a[1].split('.')[0];
  if (!g) g = $find(a[0]);
  var l1 = g._getColumnOrder('so_luong0'), l2 = g._getColumnOrder('so_luong');
  g._setItemValue(r, l1, o.checked ? g._getItemValue(r, l2): 0);
}

      &ScriptFlowGridSelect;
